PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?duration WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasSessions ?child ; p:hasConferences ?parent . } GROUP BY ?child }
  ?child p:duration ?duration .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Conferences } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?duration WHERE {
  ?conferences a :Conferences .
  ?conference_sessions a :Conference_Sessions .
  ?conference_sessions p:hasConferences ?conferences .
  ?sessions a :Sessions .
  ?conference_sessions p:hasSessions ?sessions .
  ?conferences p:name ?name .
  ?sessions p:duration ?duration .
} }
}

